1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Base premiums for single main items (base + 5 fee, first-quote: +10% first insurance) ---
6	  // Use simplest quote path. The very first quote in a scenario has no follow-up discount.
7	  it("empty item list → premium 5 G (only the processing fee)", () => {
8	    const result = runScenario({
9	      customer: { yearsWithMHPCO: 0 },
10	      steps: [{ op: "quote", items: [] }],
11	    });
12	    expect(result).toEqual({ results: [{ premium: 5 }] });
13	  });
14	  it.todo("single sword (base 100) newcomer 0yr → 100 + 10 first = 110 + 5 fee = 115 G");
15	  it.todo("single amulet (base 60) newcomer 0yr → 60 + 6 first = 66 + 5 fee = 71 G");
16	  it.todo("single staff (base 80) newcomer 0yr → 80 + 8 first = 88 + 5 fee = 93 G");
17	  it.todo("single potion (base 40) newcomer 0yr → 40 + 4 first = 44 + 5 fee = 49 G");
18	
19	  // --- Components and building blocks (base premium examples, then wrapped through modifiers) ---
20	  it.todo("single rune (base 25) newcomer 0yr → 25 + 2.5 first = 27.5 + 5 fee = 33 G (round up)");
21	  it.todo("2 runes → 50 G base premium");
22	  it.todo("3 runes → 60 G base premium (block applies)");
23	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
24	  it.todo("7 runes → 175 G base premium (one block of 3 @60 + 4 @25)");
25	
26	  // --- "Alike" components: same type only ---
27	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
28	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
29	
30	  // --- Item-specific modifiers in isolation ---
31	  it.todo("cursed sword adds 50% of its base premium (curse surcharge = 50 G on a 100 G sword)");
32	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies (+30%)");
33	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
34	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
35	
36	  // --- Modifier scope on multi-item policies ---
37	  it.todo("cursed sword (100) + plain amulet (60) → policy base 160; curse adds 50 (of sword) → 210 before policy modifiers and fee");
38	
39	  // --- Policy-wide modifiers ---
40	  it.todo("customer with exactly 2 years → 20% loyalty discount applies");
41	  it.todo("first insurance carries 10% surcharge on the policy base premium");
42	  it.todo("second quote in scenario gets 15% follow-up discount");
43	  it.todo("first insurance applies per item per quote regardless of customer history");
44	
45	  // --- Rounding ---
46	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
47	
48	  // --- Integration examples ---
49	  it.todo("newcomer cursed sword (steel, ench 3), 0yr → 165 G (100 + 50 curse + 10 first + 5 fee)");
50	  it.todo("long-standing 3yr 2nd quote, cursed sword (steel, ench 7) → 160 G (100 + 50 + 30 − 20 loyalty + 10 first − 15 follow-up + 5 fee)");
51	
52	  // --- Claim: standard reimbursement (no special clauses) ---
53	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (500 − 100 deductible)");
54	  it.todo("damage to a rune (value 250), damage 200 → payout 100 (200 − 100 deductible)");
55	
56	  // --- Claim: enchantment / dragon clauses ---
57	  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% rule wins: 500 − 100)");
58	  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon full: 800 − 100)");
59	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible: 500 − 100)");
60	  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-ench clause then deductible)");
61	
62	  // --- Claim: deductible per damage event ---
63	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");
64	
65	  // --- Claim: cap ---
66	  it.todo("policy of sword + amulet → insurance sum 1600, cap 3200");
67	  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
68	  it.todo("policy of sword + 3 runes → insurance sum 1750 (block discount does not affect sum)");
69	  it.todo("two swords → insurance sum 2000, cap 4000");
70	  it.todo("cap exhaustion: first claim 1500 → payout 1400 remainingCap 600; second claim 1500 → payout 600 remainingCap 0");
71	
72	  // --- Claim: payout rounding ---
73	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
74	
75	  // --- Multiple items of same type ---
76	  it.todo("two swords, dragon attack damages both → each sword damage entry is a separate deductible");
77	  it.todo("more damage entries of a type than the policy covers → claim rejected (non-zero exit)");
78	
79	  // --- Error cases ---
80	  it.todo("quote with unknown item type (broomstick) → error (non-zero exit, stderr, no results)");
81	  it.todo("claim references item not in policy (amulet damaged, only sword insured) → error");
82	  it.todo("claim references unknown item type → error");
83	  it.todo("claim with damage amount -200 → error");
84	
85	  // --- CLI end-to-end via runScenario ---
86	  it.todo("scenario with a quote then a claim returns results in same order");
87	});
